10	}
11	
12	export interface QuoteResult {
13	  premium: number;
14	}
15	
16	const PROCESSING_FEE = 5;
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	};
22	const FIRST_INSURANCE_SURCHARGE = 0.1;
23	
24	// Rounds up in MHPCO's favor, guarding against floating-point drift
25	// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
26	const roundUpInFavor = (amount: number): number =>
27	  Math.ceil(Number(amount.toFixed(6)));
28	
29	const itemPremium = (item: Item): number =>
30	  BASE_PREMIUMS[item.type] * (1 + FIRST_INSURANCE_SURCHARGE);
31	
32	export const quote = (customer: Customer, items: Item[]): QuoteResult => {
33	  const basePremiumTotal = items.reduce(
34	    (total, item) => total + itemPremium(item),
35	    0,
36	  );
37	  const exactPremium = basePremiumTotal + PROCESSING_FEE;
38	  return { premium: roundUpInFavor(exactPremium) };
39	};
